import { z } from 'zod';

/**
 * Onboarding Tour (SPEC-02): a repo-scoped, five-section guided tour generated by
 * grounding an LLM in a repository's deterministic index (or a README/file-tree
 * fallback). Persisted per repository as a single `json` blob (reuses the existing
 * `onboarding` table — see server `modules/onboarding/repository.ts`).
 *
 * NOTE — a legacy generic `Onboarding`/`OnboardingSection` pair already exists in
 * `./knowledge.js`. This file intentionally uses distinct names (`OnboardingTour`,
 * `TourSection`, …) to avoid that export collision; do not edit `knowledge.ts`.
 */

// ---- Section identity ----
export const TourSectionKind = z.enum([
  'architecture',
  'critical_paths',
  'how_to_run',
  'reading_path',
  'first_tasks',
]);
export type TourSectionKind = z.infer<typeof TourSectionKind>;

export const Complexity = z.enum(['low', 'medium', 'high']);
export type Complexity = z.infer<typeof Complexity>;

// ---- Architecture diagram graph ----
export const ArchNode = z.object({
  id: z.string(),
  label: z.string(),
  kind: z.string().optional(),
  outlineColor: z.string().optional(),
});
export type ArchNode = z.infer<typeof ArchNode>;

export const ArchEdge = z.object({
  from: z.string(),
  to: z.string(),
  label: z.string().optional(),
});
export type ArchEdge = z.infer<typeof ArchEdge>;

export const ArchitectureGraph = z.object({
  nodes: z.array(ArchNode),
  edges: z.array(ArchEdge),
});
export type ArchitectureGraph = z.infer<typeof ArchitectureGraph>;

// ---- Per-kind section content ----
export const ArchitectureContent = z.object({
  prose: z.string(),
  refs: z.array(z.string()),
  diagram: ArchitectureGraph,
});
export type ArchitectureContent = z.infer<typeof ArchitectureContent>;

export const CriticalPathsContent = z.object({
  rows: z.array(
    z.object({
      path: z.string(),
      why: z.string(),
    })
  ),
});
export type CriticalPathsContent = z.infer<typeof CriticalPathsContent>;

export const HowToRunContent = z.object({
  steps: z.array(
    z.object({
      command: z.string(),
      comment: z.string().optional(),
    })
  ),
});
export type HowToRunContent = z.infer<typeof HowToRunContent>;

export const ReadingPathContent = z.object({
  steps: z.array(
    z.object({
      path: z.string(),
      reason: z.string(),
    })
  ),
});
export type ReadingPathContent = z.infer<typeof ReadingPathContent>;

export const FirstTasksContent = z.object({
  tasks: z
    .array(
      z.object({
        title: z.string(),
        path: z.string(),
        complexity: Complexity,
      })
    )
    .min(2)
    .max(4),
});
export type FirstTasksContent = z.infer<typeof FirstTasksContent>;

// Discriminated by the owning TourSection's `kind` — the union is unambiguous
// because each content shape has distinct required keys (prose/rows/steps/tasks).
export const TourSectionContent = z.union([
  ArchitectureContent,
  CriticalPathsContent,
  HowToRunContent,
  ReadingPathContent,
  FirstTasksContent,
]);
export type TourSectionContent = z.infer<typeof TourSectionContent>;

// ---- Section + cost ----
export const SectionStatus = z.enum(['ready', 'generating', 'failed']);
export type SectionStatus = z.infer<typeof SectionStatus>;

export const SectionCost = z.object({
  tokensIn: z.number().int().nonnegative(),
  tokensOut: z.number().int().nonnegative(),
});
export type SectionCost = z.infer<typeof SectionCost>;

export const TourSection = z.object({
  kind: TourSectionKind,
  status: SectionStatus,
  content: TourSectionContent.nullable(),
  cost: SectionCost.nullable(),
  error: z.string().nullable(),
  generatedAt: z.string().datetime().nullable(),
});
export type TourSection = z.infer<typeof TourSection>;

// ---- Provenance ----
export const TourProvenance = z.object({
  fileCount: z.number().int().nonnegative(),
  indexed: z.boolean(),
  indexerVersion: z.number().int().nullable(),
  lastIndexedSha: z.string().nullable(),
  model: z.string(),
  githubUrl: z.string().nullable(),
});
export type TourProvenance = z.infer<typeof TourProvenance>;

// ---- Persisted tour (the `onboarding.json` payload shape) ----
export const OnboardingTour = z.object({
  repoId: z.string(),
  sections: z.array(TourSection).length(5),
  provenance: TourProvenance,
  generatedAt: z.string().datetime(),
});
export type OnboardingTour = z.infer<typeof OnboardingTour>;

// ---- API wire shapes ----
export const TourJobKind = z.enum(['whole', 'section']);
export type TourJobKind = z.infer<typeof TourJobKind>;

export const TourJobStatus = z.enum(['queued', 'running', 'failed', 'done']);
export type TourJobStatus = z.infer<typeof TourJobStatus>;

// A background `container.jobs` row for a whole-tour generation or a single
// section regeneration. `error` carries the job-level failure reason (AC-33);
// `failedSectionKinds` lists which sections failed within a whole-tour run.
// Both default to null / `[]` on success.
export const TourJob = z.object({
  id: z.string(),
  kind: TourJobKind,
  sectionKind: TourSectionKind.nullable(),
  status: TourJobStatus,
  error: z.string().nullable(),
  failedSectionKinds: z.array(TourSectionKind),
});
export type TourJob = z.infer<typeof TourJob>;

export const TourAvailability = z.enum(['unavailable', 'empty', 'ready']);
export type TourAvailability = z.infer<typeof TourAvailability>;

// Response of GET /repos/:id/tour. `job` is the LATEST job row for the repo —
// active OR most-recent terminal — so a failed job's `error` stays displayable
// even after the job itself has finished (AC-33).
export const GetTourResponse = z.object({
  availability: TourAvailability,
  tour: OnboardingTour.nullable(),
  stale: z.boolean(),
  job: TourJob.nullable(),
});
export type GetTourResponse = z.infer<typeof GetTourResponse>;
